// Names that belong to the ConceptV brand feature set (vs the general
// system/UI set). The explorer uses this to split the two groups.
window.CV_ICONS.brand = ['guided-tour', 'change-style', 'finishes', 'drone-view', 'drone', 'day-night', 'filters', 'markup', 'stages', 'furniture', 'lighting', 'convenient', 'easy', 'unique', 'web', 'gyro', 'thumbs-up', 'ownership', 'comments', 'm2', 'vr-headset', 'floorplan', 'location-pin', 'dollar-circle', 'info-circle', 'color-swatches', 'handshake', 'house', 'monitor-house'];

