  if (!AI) throw new Error('[CV_SOURCE] CV_AI must load first');
  const LS = 'atomicity:sources';
  const RECOGNIZERS = new Map(),
    ANALYZERS = new Map();
  const listeners = new Set();
  let SOURCES = load();
