          color: on ? "var(--ink)" : "var(--ink-3)",
          textAlign: "center",
          background: on ? "color-mix(in oklch, " + tint + " 34%, var(--zone-ground))" : "color-mix(in oklch, var(--pig-content) calc(3% * var(--zone-intensity)), var(--zone-ground))",
